\begin{definition}[Totally real field and CM extension]
  \label{def:TotallyRealField}
  \lean{MR4493324TheUniversalPAdicGrossZagierFormula.Basic.TODO.totallyRealField}
  \uses{lem:NumberField_mathlib}
% SOURCE: [Disegni], §1.2, Introduction (read from references/MR4493324-padic-gross-zagier.tex)
% SOURCE QUOTE: "Fix throughout the rest of this paper a rational prime  $p$. Let $F$ be a totally real field,  let $E$ be  a CM quadratic extension of $F$, and  let% In this paper, we are concerned with  the Galois  representations associated with Hilbert modular form for $F$ and their twists by  a Hecke character of a CM quadratic extension of $F$.
% $$\G_{0}:= \Res_{F/\Q}\GL_{2}, \quad \H:= \Res_{E/\Q}\G_{m}.$$"
  \textit{Source: Disegni, §1.2.}
  Fix a rational prime $p$.  Let $F$ be a totally real field and let
  $E/F$ be a CM quadratic extension.  Set
  $G_0 := \Res_{F/\bQ}\mathrm{GL}_2$ and
  $H := \Res_{E/\bQ}\mathbf{G}_m$.  Let $L$ be a finite extension of
  $\bQ_p$ splitting $F$.
\end{definition}

\begin{definition}[Quaternion algebra]
  \label{def:QuaternionAlgebra}
  \lean{MR4493324TheUniversalPAdicGrossZagierFormula.Basic.TODO.quaternionAlgebra}
  \uses{def:TotallyRealField}
% SOURCE: [Disegni], §1.3.1 (read from references/MR4493324-padic-gross-zagier.tex)
% SOURCE QUOTE: "Let $\B$ be a quaternion algebra over $F_{\A}$ (where $\A$ denotes the ad\`eles of $\Q$) with ramification set $\Sigma\sqcup \{v\vert \infty\} $ satisfying $|\Sigma| \equiv [F:\Q] -1\pmod{2}$.  Then $\G(\A):= \B^{\ts}$ is   \emph{not} the points of an algebraic group `$\G$' over $\Q$, but we will still find convenient to   use this  suggestive notation and   refer to  $\G$ as an \emph{incoherent} algebraic group over $\Q$"
  \textit{Source: Disegni, §1.3.1.}
  Let $\bB$ be a quaternion algebra over $F_{\bA}$ with ramification
  set $\Sg \sqcup \{v \mid \infty\}$ satisfying
  $|\Sg| \equiv [F:\bQ] - 1 \pmod{2}$.  Then
  $\bG(\bA) := \bB^\times$ is an \emph{incoherent} algebraic group over
  $\bQ$.  For every $v \in \Sg$ we require $E_v / F_v$ to be nonsplit;
  this guarantees a unique $\bB^\times$-conjugacy class of embeddings
  $E_{\bA} \hookrightarrow \bB$, of which we fix one, yielding
  $\mathrm{e} \colon H \hookrightarrow G$.
\end{definition}

\begin{definition}[Incoherent groups $G$, $H$, $Z$, $(G \times H)'$]
  \label{def:GroupGH}
  \lean{MR4493324TheUniversalPAdicGrossZagierFormula.Basic.TODO.groupGH}
  \uses{def:QuaternionAlgebra}
% SOURCE: [Disegni], §1.3.1 (read from references/MR4493324-padic-gross-zagier.tex)
% SOURCE QUOTE: "Let $\H=\Res_{E/\Q}{\bf G}_{m}$ as above, and let  ${\rm Z}:= \Res_{F/\Q}{\bf G}_{m}$, that admits natural central embeddings in $\G$ and $\H$.
% The list of (coherent or incoherent) groups of interest in this paper, often denoted collectively by $\G_{*}$, is
% \G, \qquad  \H, \qquad \G\times \H, \qquad (\G\times \H)':= (\G\times \H)/{\rm Z}, \qquad\H':=\H/{\rm Z},
% where ${\rm Z}$ is embedded diagonally in the product group."
  \textit{Source: Disegni, §1.3.1.}
  The groups of interest, collectively denoted $G_*$, are:
  \[
    G, \quad H, \quad G \times H, \quad (G \times H)' := (G \times H)/Z,
    \quad H' := H/Z,
  \]
  where $Z := \Res_{F/\bQ}\mathbf{G}_m$ is embedded diagonally, $G$
  is the incoherent group of \cref{def:QuaternionAlgebra}, and
  $H = \Res_{E/\bQ}\mathbf{G}_m$.
\end{definition}

\begin{definition}[Shimura varieties]
  \label{def:ShimuraVarieties}
  \lean{MR4493324TheUniversalPAdicGrossZagierFormula.Basic.TODO.shimuraVarieties}
  \uses{def:GroupGH}
% SOURCE: [Disegni], §1.3.1 (read from references/MR4493324-padic-gross-zagier.tex)
% SOURCE QUOTE: "To the above groups and suitable Shimura data (\S~\ref{ssec shi}), we associate
% corresponding towers of   compactified Shimura varieties $X_{*}$, respectively denoted
% X_{/F}, \qquad Y_{/E}, \qquad X\times_{F} Y_{/E}, \qquad Z_{/E}, \qquad Y'_{/E}.
%   They are curves except for $Y$, $Y'$ that have dimension~$0$. The embedding ${\rm e}$ induces a diagonal embedding $\H'\into (\G\times \H)'$, hence a morphism of Shimura varieties
% $${\rm e}' \colon  Y' \to Z.$$"
  \textit{Source: Disegni, §1.3.1.}
  Associated with the groups in \cref{def:GroupGH} and suitable Shimura
  data are towers of compactified Shimura varieties
  \[
    X_{/F},\quad Y_{/E},\quad (X \times_F Y)_{/E},\quad Z_{/E},\quad Y'_{/E}.
  \]
  The varieties $X$, $Z$, $X \times_F Y$ are curves; $Y$ and $Y'$ have
  dimension $0$.  The embedding $\mathrm{e} \colon H \hookrightarrow G$
  induces a diagonal embedding $H' \hookrightarrow (G \times H)'$, hence
  a morphism of Shimura varieties $\mathrm{e}' \colon Y' \to Z$.
\end{definition}

\begin{definition}[Cuspidal cohomological automorphic representation]
  \label{def:AutomorphicRepresentation}
  \lean{MR4493324TheUniversalPAdicGrossZagierFormula.Basic.TODO.automorphicRepresentation}
  \uses{def:ShimuraVarieties}
% SOURCE: [Disegni], §1.3.2 (read from references/MR4493324-padic-gross-zagier.tex)
% SOURCE QUOTE: "Let $W$ be an (algebraic) representation of $G_{*, \infty}$ over $L$, and let $\cW $ be the corresponding  \'etale local system on the tower $X_{*}$. Then we define  a (cuspidal, cohomological)  \emph{automorphic representation of $\G_{*}(\A)$ over $L$ of weight $W$} to be a representation  $$\Pi=\Pi^{\infty}\ot W$$
% of $\G_{*}(\A)$  occurring in $H^{\bullet}(X_{*, \baar{E}}, \cW^{\vee})\ot W$."
  \textit{Source: Disegni, §1.3.2.}
  Let $W$ be an algebraic representation of $G_{*,\infty}$ over $L$ and
  let $\cW$ be the corresponding \'{e}tale local system on the tower
  $X_*$.  A \emph{(cuspidal, cohomological) automorphic representation
  of $G_*(\bA)$ over $L$ of weight $W$} is a representation
  $\Pi = \Pi^\infty \otimes W$ of $G_*(\bA)$ occurring in
  $H^\bullet(X_{*,\overline{E}}, \cW^\vee) \otimes W$.
\end{definition}

\begin{definition}[Ordinary automorphic representation]
  \label{def:OrdinaryAutomorphicRep}
  \lean{MR4493324TheUniversalPAdicGrossZagierFormula.Basic.TODO.ordinaryAutomorphicRep}
  \uses{def:AutomorphicRepresentation, def:GaloisRepresentation}
% SOURCE: [Disegni], §1.2 (read from references/MR4493324-padic-gross-zagier.tex)
% SOURCE QUOTE: "Suppose that $ \pi_{0}$ is \emph{ordinary}  in the sense of Definition \ref{ord-def}; equivalently, for all $v\vert p$ the associated $G_{F_{v}}$-representation $V_{\pi_{0}, v}$ reduces nontrivially as
% $$0\to V_{\pi_{0}, v}^{+}\to V_{\pi_{0, v}}\to V_{\pi_{0}, v}^{-}\to 0,$$
% and $G_{F_{v}}$ acts on $V_{\pi_{0},v}^{+}$ by the product of the cyclotomic character $\chi_{\rm cyc}$ and a character $\alpha_{v}^{\circ}$ valued in $p$-adic units."
  \textit{Source: Disegni, §1.2.}
  An automorphic representation $\pi_0$ of $G_0(\bA)$ over $L$ is
  \emph{ordinary} if for all $v \mid p$, the associated
  $G_{F_v}$-representation $V_{\pi_0,v}$ reduces nontrivially as
  \[
    0 \to V_{\pi_0,v}^+ \to V_{\pi_0,v} \to V_{\pi_0,v}^- \to 0,
  \]
  with $G_{F_v}$ acting on $V_{\pi_0,v}^+$ via $\chi_{\mathrm{cyc}}
  \cdot \alpha_v^\circ$ where $\alpha_v^\circ$ takes values in
  $p$-adic units.
\end{definition}

\begin{definition}[Galois representation $V_\Pi$ and the sheaf $\cV$]
  \label{def:GaloisRepresentation}
  \lean{MR4493324TheUniversalPAdicGrossZagierFormula.Basic.TODO.galoisRepresentation}
  \uses{def:AutomorphicRepresentation}
% SOURCE: [Disegni], §1.3.3 (read from references/MR4493324-padic-gross-zagier.tex)
% SOURCE QUOTE: "Let $\Pi=\pi\otimes \chi$ be a cuspidal automorphic representation of $(\G\times \H)'(\A^{})$ over $L$ of weight $W=W_{\G}\ot W_{\H}$.
%     Let $V=V_{\Pi}=V_{\pi|G_{E}}\otimes V_{\chi}$ be the associated $G_{E}$-representation."
  \textit{Source: Disegni, §1.3.3.}
  For $\Pi = \pi \otimes \chi$ a cuspidal automorphic representation of
  $(G \times H)'(\bA)$ over $L$, the associated $G_E$-representation is
  $V = V_\Pi := V_{\pi|G_E} \otimes V_\chi$.

  Over a locally distinguished Hida family $\cX$
  (up to replacing $\cX$ by an open subset containing $\cX^{\mathrm{cl}}$),
  there exists a locally free sheaf $\cV$ of rank $2$ with a
  $G_{E,Sp}$-action such that $\cV_{|z} \cong V_{\Pi_z}$ for all
  $z \in \cX^{\mathrm{cl}}$ via the Langlands correspondence.
\end{definition}

\begin{definition}[Locally distinguished]
  \label{def:LocallyDistinguished}
  \lean{MR4493324TheUniversalPAdicGrossZagierFormula.Basic.TODO.locallyDistinguished}
  \uses{def:AutomorphicRepresentation, def:GaloisRepresentation}
% SOURCE: [Disegni], §1.3.4 (read from references/MR4493324-padic-gross-zagier.tex)
% SOURCE QUOTE: " \begin{defi}\lb{loc dist}
%  We say that $\Pi$ is \emph{locally distinguished by $\H'$}, or simply \emph{locally distinguished}, if it satisfies conditions $(\eps_{v}) $ for all $v$.
%  \end{defi}"
  \textit{Source: Disegni, §1.3.4, Definition (loc dist).}
  For each place $v$ of $F$, define the local epsilon factor
  \[
    \varepsilon_v^G(V) := \varepsilon(V_v)\,\chi_v(-1)\,\eta_v(-1)\,
    \varepsilon(\bB_v) \;\in\; \{\pm 1\}.
  \]
  An automorphic representation $\Pi$ of $(G \times H)'(\bA)$ is
  \emph{locally distinguished by $H'$} if $\varepsilon_v^G(V) = +1$
  for all places $v$.
\end{definition}

\begin{definition}[Global toric period pairing $Q$]
  \label{def:GlobalToricPairing}
  \lean{MR4493324TheUniversalPAdicGrossZagierFormula.Basic.TODO.globalToricPairing}
  \uses{def:LocallyDistinguished}
% SOURCE: [Disegni], §1.3.4 (read from references/MR4493324-padic-gross-zagier.tex)
% SOURCE QUOTE: "Then we define  for $f_{1}\in \Pi_{H'_{}}$, $f_{2}\in \Pi^{\vee}_{H'_{}}$, $f_{3}\in \Pi$, $ f_{4}\in \Pi^{\vee}$
% such that  $\prod_{v}(f_{3,v}, f_{4,v})_{v}\neq 0$:
% \beqq
% Q \left( {  f_{1} \ot  f_{2}\over f_{3}\ot f_{4}}\right)
% &:=
% \prod_{v}Q_{v, dt_{v}}\left( {  f_{1, v} \ot  f_{2, v}\over f_{3,v}\ot f_{4, v}}\right).
% \eeqq"
  \textit{Source: Disegni, §1.3.4.}
  For $\Pi$ locally distinguished, the local toric period
  $Q_{v,dt_v}(f_{1,v} \otimes f_{2,v} / f_{3,v} \otimes f_{4,v})$ is
  an explicit generator of $\Pi_v^{*,H'_v} \otimes (\Pi_v^\vee)^{*,H'_v}$
  normalised by the local $L$-factor $\mathscr{L}(V_{(\pi,\chi),v},0)$
  and the Haar measure $dt_v$.  Choosing measures with
  $\mathrm{vol}(H'(\bQ)\backslash H'(\bA), dt) = 1$, the \emph{global
  toric period pairing} is
  \[
    Q\!\left(\frac{f_1 \otimes f_2}{f_3 \otimes f_4}\right)
    := \prod_v Q_{v,dt_v}\!\left(\frac{f_{1,v} \otimes f_{2,v}}
    {f_{3,v} \otimes f_{4,v}}\right)
  \]
  for $f_1 \in \Pi_{H'}$, $f_2 \in \Pi^\vee_{H'}$, $f_3 \in \Pi$,
  $f_4 \in \Pi^\vee$ with $\prod_v (f_{3,v}, f_{4,v})_v \neq 0$.
\end{definition}

\begin{definition}[$p$-adic height pairing]
  \label{def:HeightPairing}
  \lean{MR4493324TheUniversalPAdicGrossZagierFormula.Basic.TODO.heightPairing}
  \uses{def:SelmerGroup, lem:OrdinaryReductionAtP}
% SOURCE: [Disegni], §1.3.5 (read from references/MR4493324-padic-gross-zagier.tex)
% SOURCE QUOTE: "if $\pi$ is ordinary  the restriction $V_{w}$ of $V$ to $G_{E_{w}}$, $w\vert p$,  is reducible
% \beq\label{ord w}
% 0\to V^{+}_{w}\to V_{w}\to V_{w}^{-}\to 0,
% \eeq
% and there is an analogous reduction  for $V^{\iota}$ such that $V^{+}_{w}$ and $V^{\iota, +}_{w}$ are exact orthogonal of each other under \eqref{pair V}.  These data
% allow
%   to define a height  pairing
% \beq \label{ht V}
%  h_{V}\colon \wtil{H}^{1}_{f}(E, V)\ot \wtil{H}^{1}_{f}(E, V^{\iota})\to L\hat{\ot}\Gamma_{F}
%  \eeq
% on \nek's Selmer groups as in Proposition \ref{prop ht}."
  \textit{Source: Disegni, §1.3.5.}
  Fix a Galois-equivariant pairing $V \otimes V^\iota \to L(1)$ where
  $V^\iota := V_{\Pi^\vee}$.  The ordinary filtrations at $w \mid p$
  from \cref{lem:OrdinaryReductionAtP} satisfy the exactness condition
  that $V_w^+$ and $V^{\iota,+}_w$ are exact orthogonal complements.
  This data determines a \emph{$p$-adic height pairing}
  \[
    h_V \colon \tH^1_f(E,V) \otimes \tH^1_f(E,V^\iota)
    \longrightarrow L \,\hat\otimes\, \GF
  \]
  on \nek's Selmer groups.

  Over the Hida family $\cX$, the interpolated duality
  $\cV \otimes \cV^\iota \to \scO_\cX(1)$ and the family of filtrations
  yield a height pairing
  \[
    h_{\cV/\cV^\iota} \colon
    \tH^1_f(E,\cV) \otimes_{\scO_\cX} \tH^1_f(E,\cV^\iota)
    \longrightarrow \cN^*_{\cX/\cX^0}
    \cong \scO_\cX \,\hat\otimes\, \GF,
  \]
  where $\cX^0$ denotes the base Hida family for $G_0 \times H$.
\end{definition}

