  \label{def:HeegnerCycle}
  \lean{MR4493324TheUniversalPAdicGrossZagierFormula.Basic.TODO.heegnerCycle}
  \uses{def:ShimuraVarieties, def:AutomorphicRepresentation}
% SOURCE: [Disegni], §1.3.6 (read from references/MR4493324-padic-gross-zagier.tex)
% SOURCE QUOTE: " Suppose that $W$ satisfies (wt), then $W^{H'_{\infty}}\cong W_{H'_{\infty}}$ is $1$-dimensional, and ${\rm e'}$ induces   a canonical system of maps
