\begin{definition}[Heegner functional $P_\Pi$]
  \label{def:HeegnerFunctional}
  \lean{MR4493324TheUniversalPAdicGrossZagierFormula.Basic.TODO.heegnerFunctional}
  \uses{def:HeegnerCycle, def:GaloisRepresentation, def:SelmerGroup}
% SOURCE: [Disegni], §1.3.6 (read from references/MR4493324-padic-gross-zagier.tex)
% SOURCE QUOTE: "Via  \eqref{cara Z},  $P_{W}$ defines  an $\H'(\A)$-invariant functional
% \beq \lb{cP Pi 0}
% P_{\Pi}\colon \Pi_{H'_{\infty}}
%  \to H^{1}(G_{E}, V_{\Pi}),
%   \eeq
% whose  image should   lie in $H^{1}_{f}(E, V_{\Pi})\subset H^{1}(E, V_{\Pi})$"
  \textit{Source: Disegni, §1.3.6.}
  Via the Carayol injection
  $\Pi \hookrightarrow \varinjlim_K \mathrm{Hom}_{L[G_E]}(H_1(\overline{Z}_K,
  \cW), V_\Pi)$, the class $P_W$ defines an $H'(\bA)$-invariant
  functional
  \[
    P_\Pi \colon \Pi_{H'_\infty} \longrightarrow H^1(G_E, V_\Pi).
  \]
  When $\Pi$ is ordinary and not exceptional, the image of $P_\Pi$
  lies in $H^1_f(E, V_\Pi)$.
  The composition $P_\Pi^{\ord} := P_W \circ \gamma^{\ord}_{H'}$ of
  $P_\Pi$ with Hida's ordinary projector operator $\gamma^{\ord}_{H'}$
  is the \emph{ordinary Heegner functional}.
\end{definition}

\begin{theorem}[Theorem B: $p$-adic Gross--Zagier formula for a fixed representation]
  \label{thm:TheoremB}
  \lean{MR4493324TheUniversalPAdicGrossZagierFormula.Basic.TODO.theoremB}
  \uses{def:HeegnerFunctional, def:HeightPairing, def:PAdicLFunction,
