        def:LocallyDistinguished}
% SOURCE: [Disegni], §1.3, Theorem B (GZ thm) (read from references/MR4493324-padic-gross-zagier.tex)
% SOURCE QUOTE: "\begin{theoA}\label{GZ thm} Let $\Pi=\pi\ot \chi$ be an ordinary, locally distinguished, non-exceptional automorphic  representation of $(\G\ts\H)'(\A^{})$ over $L$.
%  Let $V=V_{\Pi}$.
%
%
%   The image of $P_{\Pi}$ lies in $H^{1}_{f}(E, V)$, and
% for all $f_{1}\in \Pi_{H'_{\infty}}$, $f_{2}\in\Pi^{\vee}_{H'_{{\infty}}}$, $f_{3}\in \Pi$, $f_{4}\in\Pi^{\vee}$
% such that $(f_{3}, f_{4})_{\Pi}\neq 0$, we have
% $$   {  h_{V}(P_{\Pi}(f_{1}), P_{\Pi^{\vee}}(f_{2}))    \over   (f_{3}, f_{4})_{\Pi} }
% =
% e_{p\infty}(V_{(\pi, \chi)})^{-1}
%  \cdot \calL_{p}'(V_{(\pi, \chi)}, 0)
% \cdot
% Q\left( {  f_{1} \ot  f_{2}\over f_{3}\ot f_{4}}\right),
% $$
% where $e_{p\infty}(V_{(\pi, \chi)}) \in L^{\ts}$ is  the $p$-interpolation factor  for  $\calL_{p}(V_{(\pi ,\chi)}, s)$ defined in \eqref{epinf L} below.
% \end{theoA} "
  \textit{Source: Disegni, Theorem~B (§1.3).}
  Let $\Pi = \pi \otimes \chi$ be an ordinary, locally distinguished,
  non-exceptional automorphic representation of $(G \times H)'(\bA)$
  over $L$.  Let $V = V_\Pi$.

  The image of $P_\Pi$ lies in $H^1_f(E, V)$, and for all
  $f_1 \in \Pi_{H'_\infty}$, $f_2 \in \Pi^\vee_{H'_\infty}$,
  $f_3 \in \Pi$, $f_4 \in \Pi^\vee$ with $(f_3, f_4)_\Pi \neq 0$:
  \[
    \frac{h_V(P_\Pi(f_1),\, P_{\Pi^\vee}(f_2))}{(f_3, f_4)_\Pi}
    =
    e_{p\infty}(V_{(\pi,\chi)})^{-1}
    \cdot \cL_p'(V_{(\pi,\chi)}, 0)
    \cdot Q\!\left(\frac{f_1 \otimes f_2}{f_3 \otimes f_4}\right),
  \]
  where $e_{p\infty}(V_{(\pi,\chi)}) \in L^\times$ is the
  $p$-interpolation factor for $\cL_p(V_{(\pi,\chi)},s)$.
\end{theorem}

