\subsection{The universal Heegner classes}

\begin{definition}[Hida family for $(G \times H)'$]
  \label{def:HidaFamily}
  \lean{MR4493324TheUniversalPAdicGrossZagierFormula.Basic.TODO.hidaFamily}
  \uses{def:AutomorphicRepresentation, def:LocallyDistinguished}
% SOURCE: [Disegni], §1.4.2 (read from references/MR4493324-padic-gross-zagier.tex)
% SOURCE QUOTE: "Let us  fix an irreducible component
% $$\X\subset\cE^{\ord}_{K^{p}}$$
% that is a  \emph{Hida family} for $(\G\ts\H)'$. We let  $\X^{\cl}:=\X\cap\cE^{\ord, \cl}  $.
%  \begin{defi}\lb{hida loc dist}
% A {Hida family} $\X$ for $(\G\ts \H)'$
% is said to be \emph{locally distinguished} (by $\H'$) if it satisfies  the conditions
% \begin{itemize}
% \item[$(\eps_{v})'$]  for every (equivalently, one) classical point $z\in \X$ (of weight satisfying (wt)), the Galois representation $\cV_{z}$ attached to the representation $\Pi_{z}$ satisfies ($\eps_{v}$)
% \end{itemize}
% for all $v\nmid p\infty$.
% \end{defi}"
  \textit{Source: Disegni, §1.4.2.}
  Fix an open compact $K^p \subset (G \times H)'(\bA^{p\infty})$.  Let
  $\cE^{\ord}_{K^p} := \mathrm{Spec}\,\mathbf{T}^{\mathrm{sph},\ord}_{K^p,\bQ_p}$
  be the ordinary eigenvariety for $(G \times H)'$, with dense classical
  locus $\cE^{\ord,\mathrm{cl}}$.  A \emph{Hida family} is an irreducible
  component $\cX \subset \cE^{\ord}_{K^p}$; set
  $\cX^{\mathrm{cl}} := \cX \cap \cE^{\ord,\mathrm{cl}}$.

  The Hida family $\cX$ is \emph{locally distinguished} if for every
  classical point $z \in \cX^{\mathrm{cl}}$ (of weight satisfying the
  weight condition~(wt)), the attached Galois representation
  $\cV_z$ satisfies $\varepsilon_v^G(\cV_z) = +1$ for all
  $v \nmid p\infty$.
\end{definition}

\begin{lemma}[Ordinary filtration of $\cV$ at $p$]
  \label{lem:OrdinaryReductionAtP}
  \lean{MR4493324TheUniversalPAdicGrossZagierFormula.Basic.TODO.ordinaryReductionAtP}
  \uses{def:GaloisRepresentation, def:HidaFamily, def:OrdinaryAutomorphicRep}
% SOURCE: [Disegni], §1.4.3, Sheaves on $\mathscr{X}$ (read from references/MR4493324-padic-gross-zagier.tex)
% SOURCE QUOTE: "\item for each $w\vert p$ there is an exact sequence  of  $\OO_{\X}[G_{E,w}]$-modules
% \beq\label{ord fam}
%  0\to \cV_{w}^{+}\to \cV_{w}\to \cV^{-}_{w}\to 0,\eeq
% where the $\cV_{w}^{\pm} $ are line bundles  over $\X$, specialising to  \eqref{ord w} at all $z\in \X^{\cl}$;"
  \textit{Source: Disegni, §1.4.3.}
  For each $w \mid p$ there is an exact sequence of
  $\scO_\cX[G_{E_w}]$-modules
  \[
    0 \to \cV_w^+ \to \cV_w \to \cV_w^- \to 0,
  \]
  where $\cV_w^\pm$ are line bundles over $\cX$, specialising to the
  ordinary filtration $0 \to V_w^+ \to V_w \to V_w^- \to 0$ at all
  $z \in \cX^{\mathrm{cl}}$.
\end{lemma}

\begin{definition}[Universal Heegner class $\cP_{K^p}$]
  \label{def:UniversalHeegnerClass}
  \lean{MR4493324TheUniversalPAdicGrossZagierFormula.Basic.TODO.universalHeegnerClass}
  \uses{def:HeegnerFunctional, def:HidaFamily, def:SelmerGroup}
% SOURCE: [Disegni], §1.4.4 (read from references/MR4493324-padic-gross-zagier.tex)
% SOURCE QUOTE: "restricting  (without loss of generality as we will see in a moment) to the case where $W$ is trivial,  its localisation over
% $\X$ defines a global section $\cP_{K^{p}{}'}$ of
