  $\sigma \colon F \hookrightarrow \mathbf{C}$, one has
  \[
    \cL_p(\cV^\sharp)(x,y)
    = e_{p\infty}(V_{(\pi_x, \chi_y)}) \cdot
    \mathscr{L}(V_{(\pi_x, \chi_y)}, 0).
  \]
\end{definition}

\begin{definition}[Cyclotomic derivative $\mathrm{d}^\sharp \cL_p(\cV)$]
  \label{def:CyclotomicDerivative}
  \lean{MR4493324TheUniversalPAdicGrossZagierFormula.Basic.TODO.cyclotomicDerivative}
  \uses{def:PAdicLFunction, def:HidaFamily}
% SOURCE: [Disegni], §1.5.3 (read from references/MR4493324-padic-gross-zagier.tex)
% SOURCE QUOTE: "Under the condition of local distinction of $\X$,   the function  $\calL_{p}(\cV^{\sharp})$ vanishes identically on $\X_{0}$. Let   $\mathscr{N}^{*}_{\X_{0}/\X_{0}^{\sharp}} =\cI_{\X_{0}}/\cI_{\X_{0}}^{2}\ot_{\OO_{\X_{0}^{\sharp}}}\OO_{\X_{0}}  \cong \OO_{\X_{0}}\hat{\ot}\Gamma_{F}$  be the conormal sheaf and let
% $$\qquad \qquad \qquad {\rm d}^{\sharp}\calL_{p}(\cV):={\rm d}_{\X_{0}/\X_{0}^{\sharp}} \calL_{p}(\cV^{\sharp})  \qquad \in \cK(\X_{0})\hat{\ot}\Gamma_{F}= \cK(\X)\hat{\ot}\Gamma_{F}$$ be the  image of $\calL_{p}(\cV^{\sharp})$."
  \textit{Source: Disegni, §1.5.3.}
  Under the local distinction hypothesis on $\cX$, the function
  $\cL_p(\cV^\sharp)$ vanishes identically on $\cX_0$.  The conormal
  sheaf
  $\cN^*_{\cX_0/\cX_0^\sharp} = \mathcal{I}_{\cX_0}/\mathcal{I}_{\cX_0}^2
  \otimes_{\scO_{\cX_0^\sharp}} \scO_{\cX_0} \cong \scO_{\cX_0}
  \,\hat\otimes\, \GF$
  carries the \emph{cyclotomic derivative}
  \[
    \mathrm{d}^\sharp\cL_p(\cV) :=
    \mathrm{d}_{\cX_0/\cX_0^\sharp}\,\cL_p(\cV^\sharp)
    \;\in\; \cK(\cX_0)\,\hat\otimes\,\GF
    \;=\; \cK(\cX)\,\hat\otimes\,\GF.
  \]
\end{definition}

